PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE run_meta (
    run_id INTEGER PRIMARY KEY AUTOINCREMENT,
    started_at_utc TEXT NOT NULL,
    poll_interval_sec REAL NOT NULL,
    size_ladder TEXT NOT NULL,
    notes TEXT
);
CREATE TABLE yes_no_observations (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    observed_at_utc TEXT NOT NULL,
    observed_ts_ns INTEGER NOT NULL,
    venue TEXT NOT NULL,
    asset TEXT,
    duration_class TEXT,
    market_key TEXT NOT NULL,
    raw_title TEXT,
    response_age_ms REAL,
    size_usd REAL NOT NULL,
    naive_sum_top_asks REAL,
    realistic_sum_avg_asks REAL,
    yes_avg_price REAL,
    no_avg_price REAL,
    yes_filled_shares REAL,
    no_filled_shares REAL,
    yes_depth_exhausted INTEGER,
    no_depth_exhausted INTEGER,
    depth_ok INTEGER,
    fees_yes_usd REAL,
    fees_no_usd REAL,
    fees_source TEXT,
    gross_edge_usd REAL,
    net_edge_usd REAL,
    edge_per_share_usd REAL
);
CREATE TABLE cross_venue_observations (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    observed_at_utc TEXT NOT NULL,
    observed_ts_ns INTEGER NOT NULL,
    pair_key TEXT NOT NULL,
    asset TEXT,
    duration_class TEXT,
    venue_a TEXT,
    venue_b TEXT,
    a_response_ts_ns INTEGER,
    b_response_ts_ns INTEGER,
    skew_ms REAL,
    skew_unreliable INTEGER,
    size_usd REAL NOT NULL,
    naive_a_yes_top REAL,
    naive_b_no_top REAL,
    naive_sum REAL,
    realistic_sum REAL,
    a_avg_price REAL,
    b_avg_price REAL,
    a_filled_shares REAL,
    b_filled_shares REAL,
    a_depth_exhausted INTEGER,
    b_depth_exhausted INTEGER,
    depth_ok INTEGER,
    fees_a_usd REAL,
    fees_b_usd REAL,
    fees_source TEXT,
    oracle_haircut_usd REAL,
    gross_edge_usd REAL,
    net_edge_usd REAL,
    edge_per_share_usd REAL
);
CREATE TABLE errors (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    observed_at_utc TEXT NOT NULL,
    kind TEXT,
    market_key TEXT,
    detail TEXT
);
DELETE FROM sqlite_sequence;
CREATE INDEX ix_yesno_market_size ON yes_no_observations(market_key, size_usd);
CREATE INDEX ix_yesno_observed_at ON yes_no_observations(observed_at_utc);
CREATE INDEX ix_cross_pair_size ON cross_venue_observations(pair_key, size_usd);
CREATE INDEX ix_cross_observed_at ON cross_venue_observations(observed_at_utc);
COMMIT;
